@font-face {
  font-family: 'Inter';
  src: url('/fonts/Inter-Regular.woff2') format('woff2');
  font-weight: 400;
  font-style: normal;
  font-display: swap; /* Recommended for most body text to prevent FOIT */
}

@font-face {
  font-family: 'BrandHeader';
  src: url('/fonts/BrandHeader-Bold.woff2') format('woff2');
  font-weight: 700;
  font-style: normal;
  font-display: block; /* Use for critical branding; allows FOIT but guarantees custom font */
}

@font-face {
  font-family: 'IconFont';
  src: url('/fonts/IconFont.woff2') format('woff2');
  font-weight: normal;
  font-style: normal;
  font-display: optional; /* For non-critical fonts; uses system font if not loaded quickly */
}

h1 {
  font-family: 'BrandHeader', sans-serif;
}

p {
  font-family: 'Inter', sans-serif;
}
